"const { runCrawler } = require('./crawler');
const { generateBlogContent } = require('./ai_generator');
const { AutoPublisher } = require('./publisher');
const fs = require('fs');

async function main() {
    console.log('🚀 블로그 자동 포스팅 파이프라인 가동 시작!');

    // 1단계: 방송 스케줄 크롤링 (키워드 추출)
    console.log('\n--- [Phase 1: 크롤링] ---');
    await runCrawler();

    // 크롤링된 데이터 읽기
    let crawledData;
    try {
        const rawData = fs.readFileSync('crawled_data.json');
        crawledData = JSON.parse(rawData);
    } catch (e) {
        console.error('크롤링 데이터를 읽는 데 실패했습니다. 파이프라인을 중단합니다.');
        return;
    }

    const keyword = crawledData.extractedKeyword;
    if (!keyword) {
        console.error('추출된 키워드가 없습니다.');
        return;
    }
    console.log(`✅ 크롤링 완료. 타겟 키워드: ${keyword}`);

    // 2 & 3단계: 로컬 AI 원고 생성
    console.log('\n--- [Phase 2&3: AI 원고 생성] ---');
    const aiResult = await generateBlogContent(keyword);

    if (!aiResult || !aiResult.content) {
        console.error('AI 원고 생성에 실패했습니다. 파이프라인을 중단합니다.');
        return;
    }
    console.log(`✅ 원고 생성 완료. (길이: ${aiResult.content.length}자)`);

    // 4단계: 퍼블리싱 (티스토리 & 워드프레스)
    console.log('\n--- [Phase 4: 자동 포스팅 발행] ---');
    const publisher = new AutoPublisher();
    const title = `[의학정보] ${keyword}의 놀라운 효능과 부작용, 제대로 먹는 법 (전문가 가이드)`;

